import { useEffect, useMemo, useRef, useState } from 'react';
import { formatTime } from '@/tools/video-editor/lib/coordinate-utils';

const POINTER_DRAG_THRESHOLD_PX = 3;
const OVERSCAN_STEPS = 4;

export interface TimeRulerProps {
  scale: number;
  scaleWidth: number;
  scaleSplitCount: number;
  startLeft: number;
  scrollLeft: number;
  totalWidth: number;
  onClickTimeArea: (time: number) => void;
  onCursorDrag: (time: number) => void;
}

interface PointerSession {
  pointerId: number;
  startClientX: number;
  isDragging: boolean;
}

const clamp = (value: number, min: number, max: number): number => Math.min(max, Math.max(min, value));

export function TimeRuler({
  scale,
  scaleWidth,
  scaleSplitCount,
  startLeft,
  scrollLeft,
  totalWidth,
  onClickTimeArea,
  onCursorDrag,
}: TimeRulerProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const pointerSessionRef = useRef<PointerSession | null>(null);
  const [viewportWidth, setViewportWidth] = useState(0);

  const safeSplitCount = Math.max(1, scaleSplitCount);
  const contentWidth = Math.max(totalWidth, startLeft + scaleWidth);
  const pixelsPerSecond = scaleWidth / Math.max(scale, Number.EPSILON);
  const minorStepWidth = scaleWidth / safeSplitCount;
  const maxTime = Math.max(0, (contentWidth - startLeft) / pixelsPerSecond);

  useEffect(() => {
    const element = containerRef.current;
    if (!element) {
      return undefined;
    }

    const updateWidth = () => setViewportWidth(element.clientWidth);
    updateWidth();

    if (typeof ResizeObserver === 'undefined') {
      return undefined;
    }

    const observer = new ResizeObserver(updateWidth);
    observer.observe(element);
    return () => observer.disconnect();
  }, []);

  const visibleRange = useMemo(() => {
    const viewWidth = viewportWidth || contentWidth;
    const visibleLeft = Math.max(0, scrollLeft);
    const visibleRight = Math.min(contentWidth, visibleLeft + viewWidth);
    const firstMinorIndex = Math.max(
      0,
      Math.floor((visibleLeft - startLeft) / minorStepWidth) - OVERSCAN_STEPS,
    );
    const lastMinorIndex = Math.max(
      firstMinorIndex,
      Math.ceil((visibleRight - startLeft) / minorStepWidth) + OVERSCAN_STEPS,
    );

    return { firstMinorIndex, lastMinorIndex };
  }, [contentWidth, minorStepWidth, scrollLeft, startLeft, viewportWidth]);

  const majorTicks = useMemo(() => {
    const firstMajorIndex = Math.floor(visibleRange.firstMinorIndex / safeSplitCount);
    const lastMajorIndex = Math.ceil(visibleRange.lastMinorIndex / safeSplitCount);
    const ticks: Array<{ key: string; left: number; label: string }> = [];

    for (let index = firstMajorIndex; index <= lastMajorIndex; index += 1) {
      const left = startLeft + index * scaleWidth;
      if (left > contentWidth) {
        break;
      }

      ticks.push({
        key: `major-${index}`,
        left,
        label: formatTime(index * scale),
      });
    }

    return ticks;
  }, [contentWidth, safeSplitCount, scale, scaleWidth, startLeft, visibleRange.firstMinorIndex, visibleRange.lastMinorIndex]);

  const minorTicks = useMemo(() => {
    const ticks: Array<{ key: string; left: number; isMajor: boolean }> = [];

    for (let index = visibleRange.firstMinorIndex; index <= visibleRange.lastMinorIndex; index += 1) {
      const left = startLeft + index * minorStepWidth;
      if (left < startLeft || left > contentWidth) {
        continue;
      }

      ticks.push({
        key: `minor-${index}`,
        left,
        isMajor: index % safeSplitCount === 0,
      });
    }

    return ticks;
  }, [contentWidth, minorStepWidth, safeSplitCount, startLeft, visibleRange.firstMinorIndex, visibleRange.lastMinorIndex]);

  const clientXToTime = (clientX: number): number => {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) {
      return 0;
    }

    const relativeX = clientX - rect.left + scrollLeft;
    return clamp((relativeX - startLeft) / pixelsPerSecond, 0, maxTime);
  };

  const handlePointerDown = (event: React.PointerEvent<HTMLDivElement>) => {
    if (event.button !== 0) {
      return;
    }

    pointerSessionRef.current = {
      pointerId: event.pointerId,
      startClientX: event.clientX,
      isDragging: false,
    };
    event.currentTarget.setPointerCapture(event.pointerId);
    event.preventDefault();
  };

  const handlePointerMove = (event: React.PointerEvent<HTMLDivElement>) => {
    const session = pointerSessionRef.current;
    if (!session || session.pointerId !== event.pointerId) {
      return;
    }

    if (!session.isDragging && Math.abs(event.clientX - session.startClientX) >= POINTER_DRAG_THRESHOLD_PX) {
      session.isDragging = true;
    }

    if (!session.isDragging) {
      return;
    }

    onCursorDrag(clientXToTime(event.clientX));
  };

  const finishPointerSession = (
    event: React.PointerEvent<HTMLDivElement>,
    cancelled: boolean,
  ) => {
    const session = pointerSessionRef.current;
    if (!session || session.pointerId !== event.pointerId) {
      return;
    }

    pointerSessionRef.current = null;
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId);
    }

    if (cancelled) {
      return;
    }

    const time = clientXToTime(event.clientX);
    if (session.isDragging) {
      onCursorDrag(time);
      return;
    }

    onClickTimeArea(time);
  };

  return (
    <div
      ref={containerRef}
      className="relative h-[30px] overflow-hidden border-b border-border bg-muted/80 select-none"
    >
      <div
        className="absolute inset-y-0 left-0"
        style={{
          width: contentWidth,
          transform: `translateX(${-scrollLeft}px)`,
        }}
      >
        <div
          className="absolute inset-y-0 left-0 border-r border-border/70 bg-muted/95"
          style={{ width: startLeft }}
        />

        {minorTicks.map((tick) => (
          <div
            key={tick.key}
            className={tick.isMajor ? 'absolute bottom-0 w-px bg-border/80' : 'absolute bottom-0 w-px bg-border/35'}
            style={{
              left: tick.left,
              height: tick.isMajor ? '100%' : '45%',
            }}
          />
        ))}

        {majorTicks.map((tick) => (
          <div
            key={tick.key}
            className="pointer-events-none absolute left-0 top-0"
            style={{

import { describe, expect, it } from 'vitest';
import { buildTimelineData } from '@/tools/video-editor/lib/timeline-data';
import { serializeForDisk } from '@/tools/video-editor/lib/serialize';
import {
  moveTrackWithinKind,
  reorderTracksByDirection,
} from '@/tools/video-editor/hooks/useTimelineTrackManagement';
import type {
  ResolvedTimelineConfig,
  TrackDefinition,
  TrackKind,
} from '@/tools/video-editor/types';

function makeTrack(id: string, kind: TrackKind): TrackDefinition {
  return {
    id,
    kind,
    label: id,
  };
}

function getTrackOrder(tracks: TrackDefinition[]): string[] {
  return tracks.map((track) => track.id);
}

function makeResolvedConfig(tracks: TrackDefinition[]): ResolvedTimelineConfig {
  return {
    output: {
      resolution: '1280x720',
      fps: 30,
      file: 'out.mp4',
    },
    tracks,
    clips: tracks.map((track, index) => ({
      id: `clip-${track.id}`,
      at: index,
      track: track.id,
      clipType: 'hold',
      hold: 1,
    })),
    registry: {},
  };
}

describe('reorderTracksByDirection', () => {
  it('handles mixed-kind boundaries without crossing kinds', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
      makeTrack('A1', 'audio'),
      makeTrack('A2', 'audio'),
    ];

    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V2', 1))).toEqual(['V1', 'V2', 'A1', 'A2']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', -1))).toEqual(['V1', 'V2', 'A1', 'A2']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', 1))).toEqual(['V1', 'V2', 'A2', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', 1))).toEqual(['V2', 'V1', 'A1', 'A2']);
  });

  it('no-ops when each kind has only one track', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('A1', 'audio'),
    ];

    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', -1))).toEqual(['V1', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', 1))).toEqual(['V1', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', -1))).toEqual(['V1', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', 1))).toEqual(['V1', 'A1']);
  });

  it('reorders normally when all tracks share the same kind', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
      makeTrack('V3', 'visual'),
    ];

    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', 1))).toEqual(['V2', 'V1', 'V3']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V2', 1))).toEqual(['V1', 'V3', 'V2']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V3', -1))).toEqual(['V1', 'V3', 'V2']);
  });
});

describe('moveTrackWithinKind', () => {
  it('moves a track to a new position within its kind group', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
      makeTrack('V3', 'visual'),
      makeTrack('A1', 'audio'),
      makeTrack('A2', 'audio'),
    ];

    expect(getTrackOrder(moveTrackWithinKind(tracks, 'V1', 'V3'))).toEqual(['V2', 'V3', 'V1', 'A1', 'A2']);
  });

  it('allows drag moves between different kinds', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
      makeTrack('A1', 'audio'),
      makeTrack('A2', 'audio'),
    ];

    expect(getTrackOrder(moveTrackWithinKind(tracks, 'V2', 'A1'))).toEqual(['V1', 'A1', 'V2', 'A2']);
  });

  it('preserves within-kind order across serialize and buildTimelineData round-trips', async () => {
    const reorderedTracks = moveTrackWithinKind([
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
      makeTrack('A1', 'audio'),
      makeTrack('A2', 'audio'),
    ], 'V1', 'V2');

    const serialized = serializeForDisk(makeResolvedConfig(reorderedTracks));
    const rebuilt = await buildTimelineData(serialized, { assets: {} });

    expect(getTrackOrder(rebuilt.tracks)).toEqual(['V2', 'V1', 'A1', 'A2']);
  });
});

import React, {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
  type PointerEvent as ReactPointerEvent,
  type ReactNode,
  type UIEvent,
} from 'react';
import { DndContext, closestCenter, type DragEndEvent, useSensors } from '@dnd-kit/core';
import { SortableContext, useSortable, verticalListSortingStrategy } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { TrackLabelContent } from '@/tools/video-editor/components/TimelineEditor/TrackLabel';
import { TimeRuler } from '@/tools/video-editor/components/TimelineEditor/TimeRuler';
import { LABEL_WIDTH } from '@/tools/video-editor/lib/coordinate-utils';
import { snapResize } from '@/tools/video-editor/lib/snap-edges';
import type { TrackDefinition } from '@/tools/video-editor/types';
import type { TimelineAction, TimelineCanvasHandle, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import type { MarqueeRect } from '@/tools/video-editor/hooks/useMarqueeSelect';

interface ScrollMetrics {
  scrollLeft: number;
  scrollTop: number;
}

type ResizeDir = 'left' | 'right';

interface ResizeOverride {
  start: number;
  end: number;
}

interface ResizeSession {
  pointerId: number;
  actionId: string;
  rowId: string;
  dir: ResizeDir;
  initialStart: number;
  initialEnd: number;
  initialClientX: number;
}

export interface TimelineCanvasProps {
  rows: TimelineRow[];
  tracks: TrackDefinition[];
  scale: number;
  scaleWidth: number;
  scaleSplitCount: number;
  startLeft: number;
  rowHeight: number;
  minScaleCount: number;
  maxScaleCount: number;
  selectedTrackId: string | null;
  getActionRender?: (action: TimelineAction, row: TimelineRow) => ReactNode;
  onSelectTrack: (trackId: string) => void;
  onTrackChange: (trackId: string, patch: Partial<TrackDefinition>) => void;
  onRemoveTrack: (trackId: string) => void;
  onTrackDragEnd: (event: DragEndEvent) => void;
  trackSensors: ReturnType<typeof useSensors>;
  onCursorDrag: (time: number) => void;
  onClickTimeArea: (time: number) => void;
  onActionResizeStart?: (params: { action: TimelineAction; row: TimelineRow; dir: ResizeDir }) => void;
  onActionResizing?: (params: { action: TimelineAction; row: TimelineRow; start: number; end: number; dir: ResizeDir }) => void;
  onActionResizeEnd?: (params: { action: TimelineAction; row: TimelineRow; start: number; end: number; dir: ResizeDir }) => void;
  onScroll?: (metrics: ScrollMetrics) => void;
  marqueeRect?: MarqueeRect | null;
  onEditAreaPointerDown?: (event: ReactPointerEvent<HTMLDivElement>) => void;
}

const ACTION_VERTICAL_MARGIN = 4;
const CURSOR_WIDTH = 2;
const RESIZE_HANDLE_WIDTH = 8;
const MIN_ACTION_WIDTH_PX = 24;
const SNAP_THRESHOLD_PX = 8;

const clamp = (value: number, min: number, max: number): number => Math.min(max, Math.max(min, value));

const buildGridBackground = (startLeft: number, scaleWidth: number, scaleSplitCount: number, rowHeight: number): string => {
  const splitWidth = scaleWidth / Math.max(scaleSplitCount, 1);
  // Use theme-aware colors via hsl(var(--border)) and hsl(var(--background))
  return [
    `linear-gradient(to right, hsl(var(--background)) 0, hsl(var(--background)) ${startLeft}px, transparent ${startLeft}px)`,
    `repeating-linear-gradient(to right, hsl(var(--border) / 0.55) 0, hsl(var(--border) / 0.55) 1px, transparent 1px, transparent ${scaleWidth}px)`,
    `repeating-linear-gradient(to right, hsl(var(--border) / 0.25) 0, hsl(var(--border) / 0.25) 1px, transparent 1px, transparent ${splitWidth}px)`,
    `repeating-linear-gradient(to bottom, hsl(var(--border) / 0.5) 0, hsl(var(--border) / 0.5) 1px, transparent 1px, transparent ${rowHeight}px)`,
  ].join(',');
};

interface SortableRowProps {
  row: TimelineRow;
  track: TrackDefinition;
  rowHeight: number;
  startLeft: number;
  pixelsPerSecond: number;
  selectedTrackId: string | null;
  resizeOverrides: Record<string, ResizeOverride>;
  getActionRender?: (action: TimelineAction, row: TimelineRow) => ReactNode;
  onSelectTrack: (trackId: string) => void;
  onTrackChange: (trackId: string, patch: Partial<TrackDefinition>) => void;
  onRemoveTrack: (trackId: string) => void;
  onResizePointerDown: (
    event: ReactPointerEvent<HTMLDivElement>,
    action: TimelineAction,
    row: TimelineRow,
    dir: ResizeDir,
  ) => void;
  onResizePointerMove: (event: ReactPointerEvent<HTMLDivElement>) => void;
  onResizeEnd: (event: ReactPointerEvent<HTMLDivElement>, cancelled: boolean) => void;
}

function SortableRow({
  row,
  track,
  rowHeight,
  startLeft,
  pixelsPerSecond,
  selectedTrackId,
  resizeOverrides,
  getActionRender,
  onSelectTrack,
  onTrackChange,
  onRemoveTrack,
  onResizePointerDown,
  onResizePointerMove,
  onResizeEnd,
}: SortableRowProps) {
  const sortable = useSortable({ id: `track-${track.id}` });
  const actionHeight = Math.max(12, rowHeight - ACTION_VERTICAL_MARGIN * 2);
  const style = {
    height: rowHeight,
    transform: CSS.Transform.toString(sortable.transform),
    transition: sortable.transition,
    opacity: sortable.isDragging ? 0.5 : 1,
  };

  return (
    <div
      ref={sortable.setNodeRef}
      className="relative"
      data-row-id={row.id}
      style={style}
    >
      <div
        className="absolute left-0 top-0 z-10 h-full border-r border-border bg-card"
        style={{ width: LABEL_WIDTH, position: 'sticky', left: 0 }}
        onPointerDown={(event) => event.stopPropagation()}
      >
        <TrackLabelContent
          track={track}
          isSelected={selectedTrackId === track.id}
          hasClips={row.actions.length > 0}
          onSelect={onSelectTrack}
          onChange={onTrackChange}
          onRemove={onRemoveTrack}
          dragListeners={sortable.listeners}
          dragAttributes={sortable.attributes}
        />
      </div>
      {row.actions.map((action) => {
        const override = resizeOverrides[action.id];
        const renderedAction = override ? { ...action, ...override } : action;
        const left = startLeft + renderedAction.start * pixelsPerSecond;
        const width = Math.max((renderedAction.end - renderedAction.start) * pixelsPerSecond, 1);

        return (
          <div
            key={action.id}
            className="group absolute"
            data-action-id={action.id}
            data-row-id={row.id}
            style={{
              left,
              top: ACTION_VERTICAL_MARGIN,
              width,
              height: actionHeight,
            }}
          >
            {getActionRender?.(renderedAction, row)}
            <div
              className="absolute inset-y-0 left-0 z-10 cursor-ew-resize rounded-l-sm border-l border-sky-300/10 bg-sky-300/0 transition-colors group-hover:bg-sky-300/10"
              style={{ width: RESIZE_HANDLE_WIDTH }}
              onPointerDown={(event) => onResizePointerDown(event, renderedAction, row, 'left')}
              onPointerMove={onResizePointerMove}
              onPointerUp={(event) => onResizeEnd(event, false)}
              onPointerCancel={(event) => onResizeEnd(event, true)}
            />
            <div
              className="absolute inset-y-0 right-0 z-10 cursor-ew-resize rounded-r-sm border-r border-sky-300/10 bg-sky-300/0 transition-colors group-hover:bg-sky-300/10"
              style={{ width: RESIZE_HANDLE_WIDTH }}
              onPointerDown={(event) => onResizePointerDown(event, renderedAction, row, 'right')}
              onPointerMove={onResizePointerMove}
              onPointerUp={(event) => onResizeEnd(event, false)}
              onPointerCancel={(event) => onResizeEnd(event, true)}
            />
          </div>
        );
      })}
    </div>
  );
}

export const TimelineCanvas = forwardRef<TimelineCanvasHandle, TimelineCanvasProps>(function TimelineCanvas({
  rows,
  tracks,
  scale,
  scaleWidth,
  scaleSplitCount,
  startLeft,
  rowHeight,
  minScaleCount,
  maxScaleCount,
  selectedTrackId,
  getActionRender,
  onSelectTrack,
  onTrackChange,
  onRemoveTrack,
  onTrackDragEnd,
  trackSensors,
  onCursorDrag,
  onClickTimeArea,
  onActionResizeStart,
  onActionResizing,
  onActionResizeEnd,
  onScroll,
  marqueeRect,
  onEditAreaPointerDown,
}: TimelineCanvasProps, ref) {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const cursorRef = useRef<HTMLDivElement>(null);
  const resizeSessionRef = useRef<ResizeSession | null>(null);
  const resizePreviewRef = useRef<Record<string, ResizeOverride>>({});
  const timeRef = useRef(0);
  const playRateRef = useRef(1);
  const scrollMetricsRef = useRef<ScrollMetrics>({ scrollLeft: 0, scrollTop: 0 });
  const [scrollLeft, setScrollLeft] = useState(0);
  const [resizeOverrides, setResizeOverrides] = useState<Record<string, ResizeOverride>>({});

  const pixelsPerSecond = scaleWidth / Math.max(scale, Number.EPSILON);
  const minDuration = MIN_ACTION_WIDTH_PX / pixelsPerSecond;
  const maxEnd = useMemo(() => rows.reduce(
    (currentMax, row) => row.actions.reduce((rowMax, action) => Math.max(rowMax, action.end), currentMax),
    0,
  ), [rows]);
  const derivedScaleCount = Math.ceil(maxEnd / Math.max(scale, Number.EPSILON)) + 1;
  const scaleCount = clamp(derivedScaleCount, minScaleCount, maxScaleCount);
  const totalWidth = startLeft + scaleCount * scaleWidth;
  const totalHeight = Math.max(rows.length * rowHeight, rowHeight);

  const syncCursor = useCallback((time = timeRef.current) => {
    const cursor = cursorRef.current;
    if (!cursor) {
      return;
    }

    const left = startLeft + time * pixelsPerSecond;
    cursor.style.transform = `translateX(${left}px)`;
  }, [pixelsPerSecond, startLeft]);

